from flask import Flask, redirect, request, session, url_for
import requests
import os
import json

app = Flask(__name__)
app.secret_key = os.urandom(24)

CLIENT_ID = 'your_client_id'
REDIRECT_URI = 'http://localhost:5000/callback'
AUTHORIZATION_ENDPOINT = 'https://your-authorization-server.com/auth'
TOKEN_ENDPOINT = 'https://your-authorization-server.com/token'
SCOPE = 'openid'

@app.route('/')
def index():
    return 'Welcome to the Admin Dashboard. <a href="/login">Login</a>'

@app.route('/login')
def login():
    auth_url = f"{AUTHORIZATION_ENDPOINT}?client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&scope={SCOPE}&response_type=id_token"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    id_token = request.args.get('id_token')
    if id_token:
        session['id_token'] = id_token
        return redirect(url_for('dashboard'))
    return 'Authentication failed', 400

@app.route('/dashboard')
def dashboard():
    if 'id_token' not in session:
        return redirect(url_for('index'))
    return f'Hello, you are logged in! Your ID Token: {session["id_token"]}'

@app.route('/logout')
def logout():
    session.pop('id_token', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=False)